&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;Nationalisation of 14 major Commercial Banks&lt;/p&gt;

